#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int ai = *(const int*)a;
    int bi = *(const int*)b;
    return (ai > bi) - (ai < bi);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *budgets = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &budgets[i]);
        }
        qsort(budgets, N, sizeof(int), compare);
        long long maxRevenue = 0;
        for (int i = 0; i < N; ++i) {
            long long revenue = (long long)(i + 1) * budgets[i];
            if (revenue > maxRevenue) maxRevenue = revenue;
        }
        printf("%lld\n", maxRevenue);
        free(budgets);
    }
    return 0;
}

