const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let results = [];
for (let t = 0; t < T; t++) {
    const N = input[idx++];
    const budgets = input.slice(idx, idx + N);
    idx += N;
    budgets.sort((a, b) => a - b);
    let maxRevenue = 0;
    for (let i = 0; i < N; i++) {
        const revenue = (i + 1) * budgets[i];
        if (revenue > maxRevenue) maxRevenue = revenue;
    }
    results.push(String(maxRevenue));
}
console.log(results.join('\n'));

